// Byte-exact page-shell scaffolding copied from observed oracle output
// (compatibility content per clean-room protocol).
//
// Placeholders (section-sign delimited):
//   NAME IDX VERSION FILENAME  — theory identity slots
//   KIND                       — theory-kind path segment (`trace` / `equiv`)
//   DIFF                       — `<title>` prefix (`` for trace, `Diff` for equiv)
//   APPEND                     — the Actions-menu "Append modified lemmas" item
//                                (present in trace, absent in equiv/diff)
//   FLASH ROWS                 — index-page flash paragraph and theory rows

/// Full theory-view page prefix (head + north bar + Actions/Options menus, up to
/// the open west proof-script container). `KIND` selects the `/thy/<kind>/`
/// segment used in every internal link; `DIFF` prefixes the title; `APPEND` is the
/// Actions-menu append item.
pub const PAGE_PREFIX: &str = r####"<!DOCTYPE html>
<html><head><title>§DIFF§Theory: §NAME§</title><link rel="stylesheet" href="/static/css/intdot-style.css"><link rel="stylesheet" href="/static/css/tamarin-prover-ui.css"><link rel="stylesheet" href="/static/css/jquery-contextmenu.css"><link rel="stylesheet" href="/static/css/smoothness/jquery-ui.css"><script src="/static/js/jquery.js"></script></script><script src="/static/js/jquery-ui.js"></script></script><script src="/static/js/jquery-layout.js"></script></script><script src="/static/js/jquery-cookie.js"></script></script><script src="/static/js/jquery-superfish.js"></script></script><script src="/static/js/jquery-contextmenu.js"></script></script><script src="/static/js/tamarin-prover-ui.js"></script></script><script type="module" src="/static/js/intdot-graph.es.js"></script></script><script type="module" src="/static/js/intdot-staticgraph.es.js"></script></script><script type="module" src="/static/js/intdot-dynamicgraph.es.js"></script></script></head><body><p class="loading">Analyzing, please wait...  <a id=cancel href='#'>Cancel</a></p><div class="ui-layout-north"><div class="layout-pane-north"><div id="header-info">Running <a href=/><span class="tamarin">Tamarin</span></a> §VERSION§</div></div><div id="header-links"><ul id="navigation"><li><a href=/>Index</a></li><li><form class="ajax-form ajax-form-full reload-confirm" method="POST" action="/thy/§KIND§/§IDX§/reload"><button class="nav-button" type="submit">Reload file</button></form></li><li><a href="#">Actions</a><ul><li><a target=_blank href=/thy/§KIND§/§IDX§/source>Show source</a></li><li><a href=/thy/§KIND§/§IDX§/download/§FILENAME§>Download source</a></li>§APPEND§</ul></li><li><a href="#">Options</a><ul class="list-with-toggles"><li><a id=abbrv-toggle href="#">Abbreviate terms</a></li><li><a id=agent-toggle href="#">Clustering by role</a></li><li><a id=auto-toggle href="#">Show annotation auto-sources</a></li><li><a id=lvl0-toggle href="#">Graph simplification off</a></li><li><a id=lvl1-toggle href="#">Graph simplification L1</a></li><li><a id=lvl2-toggle href="#">Graph simplification L2</a></li><li><a id=lvl3-toggle href="#">Graph simplification L3</a></li></ul></li></ul></div></div><div class="ui-layout-west"><h1 class="pane-head">Proof scripts</h1><div class="scroll-wrapper" id="proof-wrapper"><div class="monospace" id="proof">"####;

/// The Actions-menu "Append modified lemmas to file" item. Substituted into the
/// `§APPEND§` slot for trace theories; the equiv/diff shell omits it.
pub const APPEND_ITEM: &str = r####"<li><form class="ajax-form" method="POST" action="/thy/§KIND§/§IDX§/get_and_append/§FILENAME§"><button class="link-button" type="submit">Append modified lemmas to file</button></form></li>"####;

pub const PAGE_MID: &str = r####"</div></div></div><div class="ui-layout-east"><h1 class="pane-head">&nbsp;Debug information</h1><div class="scroll-wrapper" id="debug-wrapper"><div id="ui-debug-display"></div></div></div><div class="ui-layout-center"><h1 class="pane-head" id="main-title">Visualization display</h1><div class="scroll-wrapper" id="main-wrapper" tabindex="0"><div id="ui-main-display">"####;

pub const PAGE_TAIL: &str = r####"</div></div></div><div id="dialog"></div><div id="confirm-dialog"></div><ul id="contextMenu"><li class="autoprove"><a href="#autoprove">Autoprove</a></a></li></ul></body></html>"####;

/// The index page (`GET /` / `POST /`). Slots: `FLASH` (an optional
/// `<p class="message">…</p>` paragraph, empty on a plain GET), `VERSION`, and
/// `ROWS` (the concatenated theory-table rows). Load timestamps and origin paths
/// inside each row are non-deterministic and supplied by the caller.
pub const ROOT_TEMPLATE: &str = r####"<!DOCTYPE html>
<html><head><title>Welcome to the Tamarin prover</title><link rel="stylesheet" href="/static/css/intdot-style.css"><link rel="stylesheet" href="/static/css/tamarin-prover-ui.css"><link rel="stylesheet" href="/static/css/jquery-contextmenu.css"><link rel="stylesheet" href="/static/css/smoothness/jquery-ui.css"><script src="/static/js/jquery.js"></script></script><script src="/static/js/jquery-ui.js"></script></script><script src="/static/js/jquery-layout.js"></script></script><script src="/static/js/jquery-cookie.js"></script></script><script src="/static/js/jquery-superfish.js"></script></script><script src="/static/js/jquery-contextmenu.js"></script></script><script src="/static/js/tamarin-prover-ui.js"></script></script><script type="module" src="/static/js/intdot-graph.es.js"></script></script><script type="module" src="/static/js/intdot-staticgraph.es.js"></script></script><script type="module" src="/static/js/intdot-dynamicgraph.es.js"></script></script></head><body>§FLASH§<p class="loading">Analyzing, please wait...  <a id=cancel href='#'>Cancel</a></p><div class="ui-layout-container"><div class="ui-layout-north"><div class="ui-layout-pane"><div class="layout-pane-north"><div class="ui-layout-pane-north"><div id="introbar"><div id="header-info">Running <a href=/><span class="tamarin">Tamarin</span></a> §VERSION§</div></div></div></div></div></div></div><div id="logo"><p><img src="/static/img/tamarin-logo-3-0-0.png"></p></div><noscript><div class="warning">Warning: JavaScript must be enabled for the <span class="tamarin">Tamarin</span> prover GUI to function properly.</div></noscript><div class="intropage"><p>Core team: <a href="https://www.inf.ethz.ch/personal/basin/">David Basin</a>, <a href="https://cispa.saarland/group/cremers/">Cas Cremers</a>, <a href="https://www.jannikdreier.net">Jannik Dreier</a>, <a href="mailto:iridcode@gmail.com">Simon Meier</a>, <a href="https://people.inf.ethz.ch/rsasse/">Ralf Sasse</a>, <a href="https://beschmi.net">Benedikt Schmidt</a><br>Tamarin is a collaborative effort: see the <a href="https://tamarin-prover.com/manual/index.html">manual</a> for a more extensive overview of its development and additional contributors.</p><p>This program comes with ABSOLUTELY NO WARRANTY. It is free software, and you are welcome to redistribute it according to its <a href="/static/LICENSE" type="text/plain">LICENSE.</a></p><p>More information about Tamarin and technical papers describing the underlying theory can be found on the <a href="https://tamarin-prover.com"><span class="tamarin">Tamarin</span> webpage</a>.</p></div><div class="intropage"><p><table><thead><th>Theory name</th><th>Time</th><th>Version</th><th>Origin</th></thead>§ROWS§</table><br></p><h2>Loading a new theory</h2><p>You can load a new theory file from disk in order to work with it.</p><form class="root-form" enctype="multipart/form-data" action="/" method="POST">Filename:<input type="file" name="uploadedTheory"><div class="submit-form"><input type="submit" value="Load new theory"></div></form><p>Note: You can save a theory by downloading the source from the Actions menu.</p></div><div id="dialog"></div><div id="confirm-dialog"></div><ul id="contextMenu"><li class="autoprove"><a href="#autoprove">Autoprove</a></a></li></ul></body></html>"####;

// --- Minimal error/status pages (Not Found, Invalid Arguments, Method Not
// Supported). All three share the standard head and tail and differ only in the
// `<title>` and the body between the loading bar and the tail.

/// Everything up to and including the opening `<title>`.
pub const SIMPLE_HEAD_A: &str = r####"<!DOCTYPE html>
<html><head><title>"####;

/// From the `</title>` through the loading bar (the fixed head link set + body
/// opener shared by every error page).
pub const SIMPLE_HEAD_B: &str = r####"</title><link rel="stylesheet" href="/static/css/intdot-style.css"><link rel="stylesheet" href="/static/css/tamarin-prover-ui.css"><link rel="stylesheet" href="/static/css/jquery-contextmenu.css"><link rel="stylesheet" href="/static/css/smoothness/jquery-ui.css"><script src="/static/js/jquery.js"></script></script><script src="/static/js/jquery-ui.js"></script></script><script src="/static/js/jquery-layout.js"></script></script><script src="/static/js/jquery-cookie.js"></script></script><script src="/static/js/jquery-superfish.js"></script></script><script src="/static/js/jquery-contextmenu.js"></script></script><script src="/static/js/tamarin-prover-ui.js"></script></script><script type="module" src="/static/js/intdot-graph.es.js"></script></script><script type="module" src="/static/js/intdot-staticgraph.es.js"></script></script><script type="module" src="/static/js/intdot-dynamicgraph.es.js"></script></script></head><body><p class="loading">Analyzing, please wait...  <a id=cancel href='#'>Cancel</a></p>"####;

/// The fixed tail shared by the error pages (no layout panes to close).
pub const SIMPLE_TAIL: &str = r####"<div id="dialog"></div><div id="confirm-dialog"></div><ul id="contextMenu"><li class="autoprove"><a href="#autoprove">Autoprove</a></a></li></ul></body></html>"####;
